// react-bot/src/App.js

import React, { Component } from 'react';
import Pusher from 'pusher-js';
import './App.css';
import {rubberBand} from 'animate.css';
import {fadeIn} from 'animate.css';

class App extends Component {
  constructor(props) {
    super(props);
    this.state = {
      userMessage: '',
      conversation: [],
    };
  }

  componentDidMount() {
    document.title = "Chow Bot"
    const pusher = new Pusher('2ce112876c7564106cb3', {
      cluster: 'us3',
      encrypted: true,
    });

    const channel = pusher.subscribe('bot');
    channel.bind('bot-response', data => {
      const msg = {
        text: data.message,
        user: 'ai',
      };

      if (data.message.slice(0, 8) === "Here are") {
        var xhttp = new XMLHttpRequest();
        xhttp.onreadystatechange = function() {
          if (this.readyState === 4 && this.status === 200) {
            //build the response
            console.log(xhttp.responseText);
          }
        };
        xhttp.open("GET", "recipes.json", true);
        xhttp.send();
      }

      var str = "Hello"
      var hyper = str.link("https://www.messenger.com/");
      const link = {
        text: hyper,
        user: 'ai',
      }

      this.setState({
        conversation: [msg, ...this.state.conversation,],
      });

      // this.setState({
      //   conversation: [link, ...this.state.conversation,],
      // });
    });
  }

  handleChange = event => {
    this.setState({ userMessage: event.target.value });
  };

  handleSubmit = event => {
    event.preventDefault();
    if (!this.state.userMessage.trim()) return;

    const msg = {
      text: this.state.userMessage,
      user: 'human',
    };

    this.setState({
      conversation: [msg, ...this.state.conversation],
    });

    fetch('/chat', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        message: this.state.userMessage,
      }),
    });

    this.setState({ userMessage: '' });
  };

  render() {
    const ChatBubble = (text, i, className) => {
      console.log(text);
      return (
        <div key= {`${className}-${i}`} className={`${className} chat-bubble`}>
          <span className="chat-content">{text}</span>
        </div>
      );
    };

    const chat = this.state.conversation.map((e, index) =>
      ChatBubble(e.text, index, e.user)
    );

    return (
      <div>
        <div className="chat-window">
          <div className="animate__animated animate__rubberBand">
          <img
            src={require("./icons/chow.png")}
            alt="logo"
            height="97.5"
            width="88.5"
            className="logo"
          />
          </div>
          <div className="animate__animated animate__fadeIn">
            <div className="conversation-view">
              {chat}
            </div>
            <div className="message-box">
              <form onSubmit={this.handleSubmit}>
                <div className = "input-container">
                  <input
                    value={this.state.userMessage}
                    onChange={this.handleChange}
                    className="text-input"
                    type="text"
                    autoFocus
                    placeholder="Let's get cooking!"
                  />
                </div>
                <div className = "button-container">
                  <button type = "submit">
                  <p id = "send"> Send </p>
                  </button>
                </div>
              </form>
            </div>
          </div>
        </div>
      </div>
    );
  }
}

export default App;
